import React, { useState, useEffect } from 'react';
import api from './api';
import BudgetForm from './components/BudgetForm';
import InvestmentForm from './components/InvestmentForm';
import AnalyticsDashboard from './components/AnalyticsDashboard';

function App() {
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [user, setUser] = useState(null);
  const [view, setView] = useState('dashboard');
  const [authView, setAuthView] = useState('login');
  const [transactions, setTransactions] = useState([]);
  const [budgets, setBudgets] = useState([]);
  const [investments, setInvestments] = useState([]);

  const login = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/login', { 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      setToken(res.data.token);
      localStorage.setItem('token', res.data.token);
      setUser(res.data.user);
      setView('dashboard');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const register = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/register', { 
        name: e.target.name.value, 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      alert('Registered successfully! Please login with your credentials.');
      setAuthView('login');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem('token');
    setView('dashboard');
  };

  const loadTransactions = async () => {
    try {
      const res = await api.get('/transactions');
      setTransactions(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadBudgets = async () => {
    try {
      const res = await api.get('/budgets');
      setBudgets(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadInvestments = async () => {
    try {
      const res = await api.get('/investments');
      setInvestments(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (token) {
      loadTransactions();
      loadBudgets();
      loadInvestments();
    }
  }, [token]);

  // Login Page (default)
  if (!token) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-900 via-purple-900 to-pink-800 flex items-center justify-center p-4 relative overflow-hidden">
        {/* Background decoration */}
        <div className="absolute inset-0">
          <div className="absolute -top-40 -right-40 w-80 h-80 bg-purple-300/20 rounded-full blur-3xl animate-pulse"></div>
          <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-indigo-300/20 rounded-full blur-3xl animate-pulse delay-1000"></div>
        </div>

        <div className="bg-white/95 backdrop-blur-xl rounded-3xl shadow-2xl p-12 max-w-md w-full border border-white/30 relative z-10 max-h-[90vh] overflow-y-auto">
          {/* Logo */}
          <div className="text-center mb-12">
            <div className="inline-flex items-center px-6 py-3 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl shadow-lg mb-6 mx-auto">
              <svg className="w-8 h-8 text-white mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span className="text-xl font-bold text-white">FinTrack</span>
            </div>
            {authView === 'login' ? (
              <>
                <h1 className="text-4xl font-black bg-gradient-to-r from-gray-800 to-gray-700 bg-clip-text text-transparent mb-3">Welcome Back</h1>
                <p className="text-gray-600 text-xl font-medium">Sign in to continue managing your finances</p>
              </>
            ) : (
              <>
                <h1 className="text-4xl font-black bg-gradient-to-r from-emerald-700 to-teal-700 bg-clip-text text-transparent mb-3">Join FinTrack</h1>
                <p className="text-gray-600 text-xl font-medium">Create your free account in seconds</p>
              </>
            )}
          </div>

          {authView === 'login' ? (
            <>
              <h2 className="text-2xl font-black text-gray-900 mb-6 text-center">Welcome Back</h2>
              <form onSubmit={login} className="space-y-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Email Address</label>
                  <input 
                    name="email" 
                    type="email" 
                    placeholder="your@email.com" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/30 focus:border-indigo-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    required 
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Password</label>
                  <input 
                    name="password" 
                    type="password" 
                    placeholder="••••••••" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/30 focus:border-indigo-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    required 
                  />
                </div>
                <button 
                  type="submit" 
                  className="w-full bg-gradient-to-r from-indigo-600 via-purple-600 to-pink-600 text-white py-6 px-8 rounded-2xl font-black text-xl shadow-2xl hover:shadow-3xl hover:from-indigo-700 hover:via-purple-700 hover:to-pink-700 transform hover:scale-[1.02] hover:-translate-y-1 transition-all duration-300 flex items-center justify-center space-x-2"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 16l-4-4m0 0l4-4m-4 4h14m-5 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h7a3 3 0 013 3v1" />
                  </svg>
                  <span>Sign In</span>
                </button>
              </form>
            </>
          ) : (
            <>
              <h2 className="text-2xl font-black text-gray-900 mb-6 text-center">Create Free Account</h2>
              <form onSubmit={register} className="space-y-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Full Name</label>
                  <input 
                    name="name" 
                    type="text" 
                    placeholder="John Doe" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    required 
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Email Address</label>
                  <input 
                    name="email" 
                    type="email" 
                    placeholder="your@email.com" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    required 
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Password</label>
                  <input 
                    name="password" 
                    type="password" 
                    placeholder="••••••••" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    minLength="6"
                    required 
                  />
                </div>
                <button 
                  type="submit" 
                  className="w-full bg-gradient-to-r from-emerald-500 to-teal-600 text-white py-6 px-8 rounded-2xl font-black text-xl shadow-2xl hover:shadow-3xl hover:from-emerald-600 hover:to-teal-700 transform hover:scale-[1.02] hover:-translate-y-1 transition-all duration-300 flex items-center justify-center space-x-2"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z" />
                  </svg>
                  <span>Create Account</span>
                </button>
              </form>
            </>
          )}

          {/* Sign up button at bottom */}
          <div className="mt-10 pt-10 border-t-2 border-indigo-100">
            <div className="text-center">
              <p className="text-lg font-semibold text-gray-600 mb-6">Don't have an account?</p>
{authView === 'login' ? (
                <button 
                  type="button"
                  onClick={() => setAuthView('register')}
                  className="w-full bg-gradient-to-r from-emerald-500 to-teal-600 text-white py-5 px-8 rounded-2xl font-bold text-xl shadow-2xl hover:shadow-3xl hover:from-emerald-600 hover:to-teal-700 transform hover:scale-[1.02] hover:-translate-y-1 transition-all duration-300 flex items-center justify-center space-x-3 group"
                >
                  <svg className="w-6 h-6 group-hover:rotate-12 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z" />
                  </svg>
                  <span>Create Free Account</span>
                </button>
              ) : (
                <button 
                  type="button"
                  onClick={() => setAuthView('login')}
                  className="w-full bg-gradient-to-r from-gray-500 to-gray-600 text-white py-5 px-8 rounded-2xl font-bold text-xl shadow-lg hover:shadow-xl hover:bg-gray-600 transition-all duration-300 flex items-center justify-center space-x-3"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 16l-4-4m0 0l4-4m-4 4h14m-5 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h7a3 3 0 013 3v1" />
                  </svg>
                  <span>Back to Sign In</span>
                </button>
              )}
              <p className="text-xs text-gray-500 mt-4 opacity-75">No credit card required • Cancel anytime</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const refreshAll = () => {
    loadTransactions();
    loadBudgets();
    loadInvestments();
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 via-blue-50 to-indigo-100">
      {/* Navigation - same as before */}
      <nav className="bg-white shadow-lg border-b border-gray-200/50 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-6 py-5 flex justify-between items-center">
          <div className="flex items-center space-x-4">
            <h1 className="text-3xl font-black bg-gradient-to-r from-indigo-600 to-purple-600 bg-clip-text text-transparent">
              FinTrack
            </h1>
            <span className="text-sm text-gray-600 font-semibold bg-indigo-100 text-indigo-700 px-4 py-1 rounded-full">Welcome, {user?.name}</span>
          </div>
          <div className="flex items-center space-x-2">
            {['dashboard', 'transactions', 'budgets', 'investments', 'analytics'].map((v) => (
              <button
                key={v}
                onClick={() => setView(v)}
                className={`px-6 py-3 rounded-2xl font-semibold text-sm transition-all duration-300 ${
                  view === v 
                    ? 'bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg hover:shadow-xl transform -translate-y-0.5' 
                    : 'text-gray-600 hover:text-indigo-600 hover:bg-indigo-50 border border-gray-200 hover:border-indigo-300'
                }`}
              >
                {v.charAt(0).toUpperCase() + v.slice(1)}
              </button>
            ))}
            <button onClick={logout} className="bg-gradient-to-r from-red-500 to-rose-600 text-white px-8 py-3 rounded-2xl font-bold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300">
              Logout
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-12">
        <div className="mb-12 flex justify-between items-center">
          <h2 className="text-4xl font-black text-gray-900 capitalize">{view}</h2>
          <button onClick={refreshAll} className="bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white px-8 py-4 rounded-2xl font-bold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300">
            Refresh Data
          </button>
        </div>

        {/* Dashboard content - keep existing */}
        {view === 'dashboard' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <AnalyticsDashboard />
            {/* Stats and other components */}
          </div>
        )}

        {/* Other views - keep existing structure */}
        {view === 'transactions' && (
          <div>
            <div className="bg-white rounded-3xl shadow-2xl p-8 mb-8">
              <BudgetForm onAdd={refreshAll} />
            </div>
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden">
              {/* Transactions table */}
            </div>
          </div>
        )}

        {/* Similar for budgets, investments, analytics */}
        {view === 'analytics' && <AnalyticsDashboard />}
      </main>
    </div>
  );
}

export default App;
